startup:
cat << EOF > /tmp/mariadb_init.sql
ALTER USER 'root'@'localhost' IDENTIFIED BY '{{MARIADB_ROOT_PASSWORD}}';
CREATE DATABASE IF NOT EXISTS {{MARIADB_DATABASE}};
CREATE USER IF NOT EXISTS '{{MARIADB_USER}}'@'%' IDENTIFIED BY '{{MARIADB_PASSWORD}}';
ALTER USER '{{MARIADB_USER}}'@'%' IDENTIFIED BY '{{MARIADB_PASSWORD}}';
GRANT ALL PRIVILEGES ON {{MARIADB_DATABASE}}.* TO '{{MARIADB_USER}}'@'%';
FLUSH PRIVILEGES;
EOF

if [ ! -d "/home/container/mysql" ]; then
    echo "Initializing MariaDB database..."
    mkdir -p /home/container/mysql
    mysql_install_db --user=$(whoami) --datadir=/home/container/mysql
fi

echo "Starting MariaDB..."
exec mariadbd --port={{SERVER_PORT}} --bind-address=0.0.0.0 --datadir=/home/container/mysql --init-file=/tmp/mariadb_init.sql
